// auth_service.dart
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthService {
  final LocalAuthentication auth = LocalAuthentication();
  static const String AUTH_SUCCESS_KEY = 'isAuthenticated';

  /// Authenticates the user using biometrics.
  /// Returns true if authentication is successful, false otherwise.
  Future<bool> authenticateWithBiometrics() async {
    bool canCheckBiometrics = await auth.canCheckBiometrics;
    bool isDeviceSupported = await auth.isDeviceSupported();

    if (!canCheckBiometrics || !isDeviceSupported) {
      // Biometrics not available on this device or not supported
      print('Biometrics not available or not supported on this device.');
      return false;
    }

    try {
      final bool didAuthenticate = await auth.authenticate(
        localizedReason: 'Please authenticate to access your account',
        options: const AuthenticationOptions(
          stickyAuth: true, // Keep authentication dialog open
          biometricOnly: true, // Only allow biometrics, no device PIN/pattern fallback
        ),
      );
      return didAuthenticate;
    } catch (e) {
      print('Error during biometric authentication: $e');
      // Handle PlatformException for specific errors if needed
      return false;
    }
  }

  /// Saves the authentication status in shared preferences.
  Future<void> saveAuthStatus(bool status) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setBool(AUTH_SUCCESS_KEY, status);
  }

  /// Retrieves the authentication status from shared preferences.
  /// Returns true if the user was previously authenticated, false otherwise.
  Future<bool> getAuthStatus() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    return prefs.getBool(AUTH_SUCCESS_KEY) ?? false;
  }

  /// Clears the authentication status from shared preferences.
  Future<void> clearAuthStatus() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove(AUTH_SUCCESS_KEY);
  }
}

